mapper.select:
SELECT l.log_id, l.work_id, l.operation_type, l.operation_time, l.operator_id, l.operation_desc, operator_user.user_name AS operator_name, w.user_id AS work_user_id, work_user.user_name AS work_user_name, d.dept_name AS user_dept_name, p.project_name, w.work_date FROM work_time_log l INNER JOIN work_time_apply w ON l.work_id = w.work_id INNER JOIN `user` work_user ON w.user_id = work_user.user_id INNER JOIN `user` operator_user ON l.operator_id = operator_user.user_id LEFT JOIN department d ON work_user.dept_id = d.dept_id LEFT JOIN project p ON w.project_id = p.project_id WHERE 1 = 1
AND l.work_id = #{workId}
AND l.operation_type = #{operationType}
AND work_user.dept_id = #{deptId}
AND w.user_id = #{currentUserId}
ORDER BY l.operation_time DESC, l.log_id DESC
